var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"옷을…… 그냥 만들어 주신다고요?","JPN":"服を……ただで作ってくださるというのですか？","ENG":"You would make costumes for us... for nothing?","TWN":"免費……替我們做嗎？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"그래. 우리 가게, 기사에도 날 만큼 옷 만드는 걸로 유명해.","JPN":"ああ。この店は記事にもなるほど、服作りで有名なのだ。","ENG":"Yup. Our store is famous for our costumes. People even write articles about them.","TWN":"沒錯，我們店還曾經因為做衣服上過報紙喔。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"물론~ 콘테스트에서 우승도 한단 말씀~ 이번엔 내가 했지만 말이야.","JPN":"もちろん～コンテストで優勝もしてるのよ～今回は私の衣装で賞を貰ったんだけどね。","ENG":"And of course, we win contests too! I was the winner this time as well.","TWN":"不只如此～也曾經在比賽中獲獎喔～順帶一提，那次是我做的喔。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"전에도 얘기했지만, 그런 잡탕 옷으로 우승한 건 인정 못해.","JPN":"前にも話したが、そのような雑な服で優勝したのは認めない。","ENG":"Like I said before, I won't accept such a contradiction of an outfit winning.","TWN":"我之前就說過，拼拼湊湊做出來的衣服會贏，我絕對無法認同。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"옷이란 모름지기 확고한 컨셉이 있어야 한단 말이야.","JPN":"服とは、確かなコンセプトがあって然るべきなのだ。","ENG":"An outfit has to express a clear idea.","TWN":"衣服的設計主軸要很明確才對。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"후후. 진 사람들은 보통 그런 핑계를 대곤 하더라~","JPN":"ふふ。負けた人って大体がそんな言い訳をするのよね～","ENG":"Haha. Losers often make excuses like that.","TWN":"呵呵～輸的人才那麼多藉口～"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"흥. 맘대로 생각해. 이번에 아주 좋은 영감이 떠올랐으니까.","JPN":"フン。勝手に思うがいい。とてもいいインスピレーションが湧いたんだ。","ENG":"Hmph, whatever. I have a great inspiration this time.","TWN":"哼，隨你怎麼說，這次我有很棒的靈感。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"콘테스트는 아니어도 꽤 훌륭한 녀석이 탄생할걸?","JPN":"コンテストでなくても、かなりの傑作が生まれるぞ。","ENG":"It's not for a contest, but it's gonna be something pretty grand.","TWN":"雖然不是在比賽，但我會做出很厲害的作品喔。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"축제에서 모두의 이목을 끌 수 있을 거야.","JPN":"お祭りで大衆の目を引くことうけあいだ。","ENG":"It'll make you the star of the festival.","TWN":"一定會讓她們在活動上成為眾人的焦點。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그럼 지하실에서 재료들을 좀 모아야겠네~ 고생 좀 하겠어?","JPN":"じゃあ、地下室で材料を集めてこないとね～苦労しそうだわ。","ENG":"You're going to have to get some materials from the basement, then! Good luck.","TWN":"那你要去地下室收集一些材料吧～會有點辛苦喔？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"혹여나 제 도움이 필요하시다면……","JPN":"もし、私の協力が必要でしたら……","ENG":"If you need some help, I can–","TWN":"需要我幫助的話……"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"지하실은 외부인 출입 금지야. 거기까진 신경 써줄 것 없어.","JPN":"地下室は部外者立ち入り禁止だ。そこまで気にすることはない。","ENG":"The basement is off-limits to non-staff members. You don't need to concern yourself with that.","TWN":"地下室禁止外人進入，不需要你費心。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"게다가 내 변덕이기도 하고, 이번 일은 나 혼자서 할게. 의상 하나 분의 재료 정도는 쉽게 채집할 수 있어.","JPN":"それに、妾の気まぐれでもあるし、この件は妾一人でやろう。衣装一着分の材料くらい簡単に採集できる。","ENG":"Plus, I'm the one who wants to do this. So I'll take care of it alone. It's not difficult to get materials for one costume.","TWN":"而且這是我自己想做的，我會自己處理。要收集一件衣服的材料很容易的。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"불만은 없지만, 정말 나 없이도 괜찮을까?","JPN":"不満はないけど、本当に私がいなくても大丈夫なのかしら。","ENG":"I don't have an issue with that, but are you sure you'll be all right without me?","TWN":"我是無所謂，但你確定不需要我的幫忙嗎？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"저 두 녀석한테 카페를 맡기는 게 더 불안해. 무슨 사고를 칠 줄 알고?","JPN":"あの二人にカフェを任せる方がよっぽど不安だ。何をしでかすかわからない。","ENG":"I'd be more worried if I left the cafe in those dummies' hands. Who knows what kind of trouble they're going to cause?","TWN":"把咖啡廳交給那二個傢伙我更擔心，誰知道她們會給我惹什麼麻煩？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그럼 나 대신 호위 무사님을 데려가는 건 어때?","JPN":"じゃあ、私の代わりに護衛さんを連れて行くのはどう？","ENG":"Why don't you take Miss Bodyguard instead, then?","TWN":"不讓我去的話，那至少帶上護衛武士呢？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"뭐? 제정신으로 하는 소리야? 거긴…….","JPN":"は？　正気か？　あそこは……","ENG":"What? Are you serious? The basement is...","TWN":"什麼？你是認真的嗎？那裡……"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"라우라 혼자 지하실로 보내는 건 걱정이 되는걸?","JPN":"ラウラ一人で地下室に行かせるのは心配だもの。","ENG":"Well, I don't want to send you alone to the basement all alone.","TWN":"我不放心讓蘿拉一個人去地下室。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"길 가다가 넘어져서 엉엉 울어버리면 어떡해?","JPN":"歩いてる途中に転んじゃって、びえーんと泣いちゃったらどうするのよ。","ENG":"What if you trip and start crying?","TWN":"萬一你不小心跌倒放聲大哭怎麼辦？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"누굴 애 취급하고 있어. 플루토도 같이 가는데 무슨 걱정이야?","JPN":"子ども扱いするな。プルートも一緒に行くのに何が心配なんだ。","ENG":"Quit treating me like a child. Pluto will go with me, you don't need to worry.","TWN":"我又不是小朋友，布魯托也會一起去，有什麼好擔心的？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"한 번씩 강한 녀석들이 나타나잖아. 아무리 플루토가 있더라도 돌발상황은 위험해.","JPN":"たまに強い奴らが現れるじゃない。いくらプルートがいるって言っても、突発的な状況は危ないわ。","ENG":"You know that a strong one pops out every once in a while. Even with Pluto by your side, it might be dangerous.","TWN":"偶爾也會有厲害的傢伙出現，就算有布魯托在，萬一有什麼突發狀況我怕會有危險。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저희 도움이 필요한 일이라면 도와드리겠습니다.","JPN":"私たちが協力できることでしたら、お手伝いします。","ENG":"We will gladly help if it is required.","TWN":"要是需要我們的幫忙，我們很樂意。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"꼬마 무녀님도 가세하면 우리야 고맙지~","JPN":"ちびっ子巫女さんが手伝ってくれるなら心強いわ～","ENG":"We would be grateful for your assistance as well, little priestess!","TWN":"小巫女願意幫忙的話，我們當然是很感激囉～"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저, 전 꼬마가 아닙니다.","JPN":"わ、私はちびっ子ではありません。","ENG":"I-I am not little.","TWN":"我，我才不是小朋友。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저는 나나하라 가문 연합을 이끄는 당주 나나하라……","JPN":"私は七原家連合を率いる当主、七原……","ENG":"I am the head of the Nanahara Family Alliance–","TWN":"我是七原家族的堂主七原……"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"어유~ 그래. 귀여운 숙녀 당주님. 같이 도와줄 수 있지?","JPN":"はいはい。可愛い当主のお嬢ちゃん。一緒に手伝ってくれる？","ENG":"Aww, sure you are, you adorable lady. You want to help?","TWN":"好好好～可愛的小淑女堂主，你們可以一起幫忙嗎？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};